  ('judicial-792a7dff-moex-00051', 'judicial-792a7dff', 'judicial-792a7dff-moex-112-38f6539c', 'sub-judicial-792a7dff-02', NULL, 'essay', '甲簽發發票日為民國 107 年 7 月7 日，到期日為同年 9 月 9日，面額新
臺幣 200 萬元，記載受款人為乙，付款地為臺中市之本票 1張（下稱系
爭本票），先經丙背書後，再由甲交付乙。系爭本票屆期經提示未獲付款，
乙於 112 年 5 月5 日持系爭本票，聲請臺灣臺中地方法院（下稱臺中地
院）裁定許可對甲、丙為強制執行，甲、丙均為時效消滅之抗辯。問：
臺中地院應如何處理？（25分）
10680', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:56+00:00", "source_pdf_sha1": "aba322c8cb80", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "106", "s": "0413", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法與非訟事件法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00052', 'judicial-792a7dff', 'judicial-792a7dff-moex-112-38f6539c', 'sub-judicial-792a7dff-02', NULL, 'essay', '甲於民國 105 年 9 月 9 日向乙借款新臺幣（下同）500 萬元，並簽交同
額本票 1 張及以其所有坐落臺中市之 A土地，設定最高限額抵押權 600
萬元（下稱系爭抵押權）以為擔保，甲屆期未為清償，乙乃以該本票及
抵押權之證明文件聲請臺灣臺中地方法院（下稱臺中地院）以准許拍賣
抵押物之裁定（下稱系爭裁定）為執行名義，聲請臺中地院拍賣A土地。
甲於執行程序進行中，以該本票債權業經法院判決確認不存在確定，系
爭裁定之執行力亦確定不存在，不得再為強制執行為由，向臺中地院聲
明異議。乙又提出借據為債權證明文件，另向臺中地院聲請准許拍賣 A
土地之裁定。問：臺中地院就該聲請應如何處理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:56+00:00", "source_pdf_sha1": "aba322c8cb80", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "106", "s": "0413", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法與非訟事件法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00053', 'judicial-792a7dff', 'judicial-792a7dff-moex-112-69fcaee1', 'sub-judicial-792a7dff-03', NULL, 'essay', '甲自民國 100 年 7 月起受僱於乙，指派至乙出資之 A 藥局掛名負責人
藥師，惟一切事務均由乙做決策與處理。甲則支領固定薪資，詎乙租借
他人牌照申報健保費用，因此甲以負責人身分被罰處新臺幣（下同）200
萬元之罰鍰（下稱系爭罰鍰）。甲認為其只是擔任 A 藥局掛名負責人，
系爭罰鍰應由乙支出，試問甲所受支出 200 萬元之損害該如何向乙主
張？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:56+00:00", "source_pdf_sha1": "cf2a25abda95", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "106", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法與刑法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00054', 'judicial-792a7dff', 'judicial-792a7dff-moex-112-69fcaee1', 'sub-judicial-792a7dff-03', NULL, 'essay', '甲向乙買受 A地及 A地上之違章建物 B屋，乙依約辨理 A地之移轉登
記，並交付 B屋於甲。嗣後 B 屋卻遭丙無權占用，試問甲得否主張所
有物返還請求權，向丙請求返還B屋？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:56+00:00", "source_pdf_sha1": "cf2a25abda95", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "106", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法與刑法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00055', 'judicial-792a7dff', 'judicial-792a7dff-moex-112-69fcaee1', 'sub-judicial-792a7dff-03', NULL, 'essay', '甲、A同在一間辦公室工作，平日相處不睦，甲出於損人不利己的報復
動機，唆使另一同事乙找機會將A工作的重要財物丟棄，乙應允。某日，
乙看到 A離開座位，將 A的隨身碟從其座位取走後，以隨身碟最後可能
被如何處置都無所謂的心態，將 A 的隨身碟順手置入同事 B 的公事包
內。A下班前發現隨身碟遺失，非常緊張，請同事幫忙在辦公室尋找，
卻沒有找到。B 回家整理公事包時，發現有一個陌生隨身碟，想起當天
辦公室 A在找隨身碟的事情，雖不知隨身碟為什麼會在公事包出現，仍
在隔日問 A是否為其遺失的隨身碟，A確認後非常高興，隨身碟失而復
得。試問甲、乙之行為依刑法應如何論罪？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:56+00:00", "source_pdf_sha1": "cf2a25abda95", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "106", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法與刑法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00056', 'judicial-792a7dff', 'judicial-792a7dff-moex-112-69fcaee1', 'sub-judicial-792a7dff-03', NULL, 'essay', '甲在外租屋，為了防盜理由，甲在房間安裝監視器。某日甲的好友 A知
悉甲因工作因素需出國二週，A向甲商議在其出門期間，借用甲的房間
住宿，甲同意但約定 A不得帶他人回家，卻忘記告訴 A房間有監視器。
A不知該房間設有監視系統，在住宿期間常全身未著任何衣物，全裸在
房間走動，有日 A 約同其親密好友 B，在甲的房間內共餐，其間 A、B
二人有親吻行為。甲回家從監視器存檔資料，發現 A竟違反約定帶友人
回家，甲質問 A時，A始知借宿期間，生活日常以及與 B的私密親吻行
為皆被監視器拍攝，A要求甲將資料刪除，甲認為其為房間使用人，當
然可以在自己的住處裝設監視器，只含糊答應，卻沒有積極刪除資料。
試問甲的行為依刑法應如何評價？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:56+00:00", "source_pdf_sha1": "cf2a25abda95", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "106", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法與刑法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00057', 'judicial-792a7dff', 'judicial-792a7dff-moex-112-9bdab6d6', 'sub-judicial-792a7dff-04', NULL, 'essay', '依我國稅捐稽徵法規定，檢舉逃漏稅捐或其他違反稅法規定之情事，經
查明屬實，且裁罰確定並收到罰鍰者，稅捐稽徵機關應以收到之罰鍰提
成核發獎金與舉發人，試問有關檢舉獎金之核發規定為何？檢舉案件有
那些情形不適用核發獎金之規定，請說明之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:56+00:00", "source_pdf_sha1": "f1bafd39ba6a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "106", "s": "0904", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00058', 'judicial-792a7dff', 'judicial-792a7dff-moex-112-9bdab6d6', 'sub-judicial-792a7dff-04', NULL, 'essay', '林先生目前擁有2 間房產，占地各 1 公畝，A縣市的房產公告地價新臺
幣（下同）1,700萬元，公告現值 2,400 萬元，未申報地價，做出租使用；
B縣市的房產公告地價 1,200萬元，申報地價 1,500 萬元，公告現值2,000
萬元，做自住使用，並符合自用住宅用地之條件，經向稽徵機關申請獲
准。假設 A縣市之累進起點地價為 400萬元，B縣市之累進起點地價為
300 萬元，試問：（請詳列計算式，否則不予計分）
位於 A縣市的房屋，其應繳納地價稅為多少？（13分）
